#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define rg register
using namespace std;
typedef long long LL;
inline int read()
{
	rg int res=0;rg char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline LL Max(LL x,LL y){return x>y?x:y;}
const int N=3010,NN=2e6+10;
int buf[NN];int *a[N],v[N],n,k;
long long buf2[N*N], dp[N],ans,w[N];
inline void Solve(int l,int r,long long *sv)
{
	if(l==r)
	{
		LL res=0;int lm=(v[l]<k?v[l]:k);ans=Max(ans,dp[k]);
		rep(1,lm,i)
		{
			ans=Max(ans,dp[k-i]+(res+=a[l][i]));
//			printf("%lld %lld\n",dp[k-i],res);
		}
		return;
	}
	memcpy(sv,dp,(k+1)<<3);int mid=(l+r)>>1;
	rep(l,mid,i)drep(k,v[i],j)dp[j]=Max(dp[j],dp[j-v[i]]+w[i]);
	Solve(mid+1,r,sv+k+1);memcpy(dp,sv,(k+1)<<3);
	rep(mid+1,r,i)drep(k,v[i],j)dp[j]=Max(dp[j],dp[j-v[i]]+w[i]);
	Solve(l,mid,sv+k+1);return;
}
int main()
{
	n=read(),k=read();a[1]=buf;rep(1,n,i)
	{
		v[i]=read();a[i+1]=a[i]+v[i];
		rep(1,v[i],j)w[i]+=a[i][j]=read();
	}
	Solve(1,n,buf2);printf("%lld\n",ans);return 0;
}
